200	          { type: "rune" },
201	          { type: "rune" },
202	          { type: "rune" },
203	          { type: "rune" },
204	          { type: "rune" },
205	          { type: "rune" },
206	          { type: "rune" },
207	        ],
208	      })
209	    ).toBe(198);
