239	  it.todo("sword (cap 2000 G), first claim 1500 G yields payout 1400 G, remainingCap 600 G");
240	  it.todo("sword (cap 2000 G), after first 1500 G claim, second 1500 G claim yields payout 600 G, remainingCap 0 G");
241	
242	  // ===== Claim: multiple items of same type =====
243	  it.todo("policy covers two swords: insurance sum 2000 G, cap 4000 G");
244	  it.todo("dragon attack damages both insured swords: each entry treated separately with own deductible");
245	
