3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
23	const LOYALTY_DISCOUNT_RATE = 0.2;
24	const LOYALTY_YEARS_THRESHOLD = 2;
25	const CURSED_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const COMPONENT_BASE = 25;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	
31	const ITEM_BASE_PREMIUMS: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	function isComponentType(type: string): boolean {
41	  return ITEM_BASE_PREMIUMS[type] === COMPONENT_BASE;
42	}
43	
44	function groupItemsByType(items: Item[]): Map<string, Item[]> {
45	  const groups = new Map<string, Item[]>();
46	  for (const item of items) {
47	    const group = groups.get(item.type) ?? [];
48	    group.push(item);
49	    groups.set(item.type, group);
50	  }
51	  return groups;
52	}
53	
54	function totalSurchargeRate(item: Item): number {
55	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
56	  const highEnchantmentRate =
57	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
58	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
59	      : 0;
60	  return cursedRate + highEnchantmentRate;
61	}
62	
63	function calculateItemSurcharge(type: string, item: Item): number {
64	  const base = ITEM_BASE_PREMIUMS[type];
65	  return base * totalSurchargeRate(item);
66	}
67	
68	function calculateGroupBase(type: string, group: Item[]): number {
69	  if (isComponentType(type) && group.length === 3) {
70	    return COMPONENT_BLOCK_PREMIUM;
71	  }
72	  return group.reduce((sum) => sum + ITEM_BASE_PREMIUMS[type], 0);
73	}
74	
75	function calculatePolicyBase(items: Item[]): number {
76	  const groups = groupItemsByType(items);
77	  return Array.from(groups).reduce(
78	    (total, [type, group]) => total + calculateGroupBase(type, group),
79	    0
80	  );
81	}
82	
83	function calculateItemSurcharges(items: Item[]): number {
84	  return items.reduce(
85	    (total, item) => total + calculateItemSurcharge(item.type, item),
86	    0
87	  );
88	}
89	
90	function calculateLoyaltyDiscount(customer: Customer, policyBase: number): number {
91	  if (customer.yearsWithMHPCO < LOYALTY_YEARS_THRESHOLD) {
92	    return 0;
93	  }
94	  return policyBase * LOYALTY_DISCOUNT_RATE;
95	}
96	
97	function calculateFollowUpDiscount(customer: Customer, policyBase: number): number {
98	  const hasPreviousContracts = (customer.previousContracts ?? 0) >= 1;
99	  if (!hasPreviousContracts) {
100	    return 0;
101	  }
102	  return policyBase * FOLLOW_UP_DISCOUNT_RATE;
103	}
104	
105	function calculateFirstInsuranceSurcharge(policyBase: number): number {
106	  return policyBase * FIRST_INSURANCE_RATE;
107	}
108	
109	export function quote(input: QuoteInput): number {
110	  const policyBase = calculatePolicyBase(input.items);
111	  const itemSurcharges = calculateItemSurcharges(input.items);
112	  const firstInsuranceSurcharge = calculateFirstInsuranceSurcharge(policyBase);
113	  const loyaltyDiscount = calculateLoyaltyDiscount(input.customer, policyBase);
114	  const followUpDiscount = calculateFollowUpDiscount(input.customer, policyBase);
115	  return Math.ceil(
116	    policyBase +
117	      itemSurcharges +
118	      firstInsuranceSurcharge +
119	      PROCESSING_FEE -
120	      loyaltyDiscount -
121	      followUpDiscount
122	  );
123	}
